            if (this.timeRemaining <= 0) {
                clearInterval(interval);
                alert('Game Over!');
                location.reload();
                return;
            }
            this.timeRemaining--;
            const mins = Math.floor(this.timeRemaining / 60);
            const secs = this.timeRemaining % 60;
            timerEl.innerText = `${mins}:${secs.toString().padStart(2, '0')}`;
