            if (e.code === 'Digit6') this.weaponSystem.switchWeapon('GRENADE');
            if (e.code === 'Digit7') this.weaponSystem.switchWeapon('SWORD');
            if (e.code === this.keybinds.reload) this.weaponSystem.reload();
