            if (!this.isLocked || this.platform !== 'PC') return;
            const sensitivity = this.weaponSystem.isZoomed ? 0.0005 : 0.002;
            this.playerRotation.y -= e.movementX * sensitivity;
            this.playerRotation.x -= e.movementY * sensitivity;
