        const list = document.getElementById('leaderboard-list');
        list.innerHTML = '';

        // Add self to leaderboard
        const players = [{ id: 'YOU', kills: this.kills, deaths: this.deaths }, ...Object.values(this.networkManager.remotePlayerData || {})];
