        window.addEventListener('contextmenu', (e) => e.preventDefault());

        document.addEventListener('pointerlockchange', () => {
            this.isLocked = document.pointerLockElement === this.renderer.domElement;
            if (this.gameStarted && !this.isLocked && this.platform === 'PC') {
                document.getElementById('menu-container').style.display = 'flex';
                document.getElementById('platform-screen').classList.add('active');
                document.getElementById('map-screen').classList.remove('active');
                document.getElementById('mode-screen').classList.remove('active');
