                currentIndex = (currentIndex + 1) % weaponKeys.length;
            } else {
                currentIndex = (currentIndex - 1 + weaponKeys.length) % weaponKeys.length;
            }
            this.weaponSystem.switchWeapon(weaponKeys[currentIndex]);
        });

        this.lastTouchPos = {};
        this.setupMobileEvents();
    }

    setupMobileEvents() {
