                    this.keys[this.keybinds.forward] = dy < -20;
                    this.keys[this.keybinds.backward] = dy > 20;
                    this.keys[this.keybinds.left] = dx < -20;
                    this.keys[this.keybinds.right] = dx > 20;
                } else if (touch.clientX > window.innerWidth / 2) {
