        if (this.onGround) this.verticalVelocity = Math.max(0, this.verticalVelocity);

        this.camera.position.set(nextPos.x, nextPos.y + 0.6, nextPos.z);
        this.camera.quaternion.setFromEuler(this.playerRotation);
    }

