            const data = this.networkManager.remotePlayerData[id];
            if (!data || !data.healthBar) return;

            const vector = new THREE.Vector3();
            mesh.getWorldPosition(vector);
            vector.y += 1.2; // Above head
            vector.project(this.camera);

            if (vector.z > 1) {
