        this.setupConnection(conn);
    }

    setupConnection(conn) {
        conn.on('open', () => {
            this.connections[conn.peer] = conn;
            console.log('Connected to: ' + conn.peer);

            // If host, send current settings to the new player
            if (this.isHost) {
                conn.send({
                    type: 'settings',
                    map: this.game.selectedMap,
                    mode: this.game.selectedMode
                });
            }

            // Send initial join message
            conn.send({ type: 'join', id: this.myId });
        });

        conn.on('data', (data) => {
            this.handleMessage(conn.peer, data);
        });

        conn.on('close', () => {
            this.removeRemotePlayer(conn.peer);
            delete this.connections[conn.peer];
        });
    }

    handleMessage(peerId, data) {
        if (data.type === 'join') {
            this.createRemotePlayer(peerId);
        } else if (data.type === 'settings') {
            // Joiner receives settings from host
            this.game.selectedMap = data.map;
            this.game.selectedMode = data.mode;
            document.getElementById('menu-container').style.display = 'none';
