        this.scene.add(mesh);
        this.projectiles.push({ mesh, velocity: dir.multiplyScalar(20), life: 2.0 });
    }

    createImpactEffect(point, color, size = 0.05) {
        const geo = new THREE.SphereGeometry(size, 4, 4);
