        window.addEventListener('wheel', (e) => {
            if (this.platform === 'PC' && !this.isLocked) return;
            const weaponKeys = Object.keys(WEAPON_DATA);
            let currentIndex = weaponKeys.indexOf(this.weaponSystem.currentWeaponKey);

