        }

        // Area of effect damage
        const nm = window.gameInstance.networkManager;
        if (!nm) return;
        Object.keys(nm.remotePlayers).forEach(id => {
            const mesh = nm.remotePlayers[id];
            if (mesh.position.distanceTo(point) < 5) {
