        <div class="mobile-btn" id="btn-jump">JUMP</div>
        <div class="mobile-btn" id="btn-reload">RELOAD</div>
        <div class="mobile-btn" id="btn-switch">NEXT</div>
        <div class="mobile-btn" id="btn-scope">SCOPE</div>
    </div>

    <div id="settings-modal">
        <h2>Keybinds</h2>
        <div id="bind-list"></div>
        <button id="end-game-btn" style="margin-top:10px; width:100%; padding:10px; cursor:pointer; background:#ff4444; color:white; border:none; border-radius:5px;">End Game</button>
        <button id="close-settings" style="margin-top:10px; width:100%; padding:10px; cursor:pointer;">Close</button>
    </div>

    <div id="hud-bottom-left">
        <div id="local-health-container"><div id="local-health-fill"></div></div>
        <div id="weapon-name" style="font-size: 24px; font-weight: bold;">Rifle</div>
        <div id="ammo" style="font-size: 18px; opacity: 0.8;">30 / 90</div>
        <div id="reload-msg" style="display:none; color: #ff4444; font-weight: bold; margin-top:5px; animation: blink 1s infinite;">PRESS R TO RELOAD</div>
    </div>

    <div id="hud-bottom-center">
        <div id="weapon-toolbar" style="display:flex; gap:8px;"></div>
    </div>

    <script type="module" src="./main.js"></script>
    <script>
        // Use a more robust way to handle global menu calls
        function selectPlatform(p) {
            if (window.gameInstance) window.gameInstance.onPlatformSelect(p);
            else console.error("Game instance not ready");
        }
        function selectMap(m) {
            if (window.gameInstance) window.gameInstance.onMapSelect(m);
            else console.error("Game instance not ready");
        }
        function selectMode(mo) {
            if (window.gameInstance) window.gameInstance.onModeSelect(mo);
            else console.error("Game instance not ready");
        }

        // Expose to window for onclick handlers
        window.selectPlatform = selectPlatform;
        window.selectMap = selectMap;
        window.selectMode = selectMode;
    </script>
</body>
